1	import { useState, useEffect } from "react";
2	import { Link, useNavigate } from "react-router-dom";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { supabase } from "@/integrations/supabase/client";
8	import { useToast } from "@/hooks/use-toast";
9	import { Eye, EyeOff, Loader2, ShieldCheck } from "lucide-react";
10	import { cn } from "@/lib/utils";
11	
12	const ResetPassword = () => {
13	  const navigate = useNavigate();
14	  const { toast } = useToast();
15	  const [password, setPassword] = useState("");
16	  const [confirmPassword, setConfirmPassword] = useState("");
17	  const [showPassword, setShowPassword] = useState(false);
18	  const [isLoading, setIsLoading] = useState(false);
19	  const [isRecovery, setIsRecovery] = useState(false);
20	  const [passwordErrors, setPasswordErrors] = useState<string[]>([]);
21	
22	  const validatePassword = (pwd: string): string[] => {
23	    const errors: string[] = [];
24	    if (pwd.length < 8) errors.push("At least 8 characters");
25	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
26	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
27	    if (!/[0-9]/.test(pwd)) errors.push("One number");
28	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
29	    return errors;
30	  };
31	
32	  useEffect(() => {
33	    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
34	      if (event === "PASSWORD_RECOVERY") {
35	        setIsRecovery(true);
36	      }
37	    });
38	
39	    // Check hash for recovery token
40	    const hash = window.location.hash;
41	    if (hash && hash.includes("type=recovery")) {
42	      setIsRecovery(true);
43	    }
44	
45	    return () => subscription.unsubscribe();
46	  }, []);
47	
48	  const handlePasswordChange = (value: string) => {
49	    setPassword(value);
50	    setPasswordErrors(validatePassword(value));
51	  };
52	
53	  const handleSubmit = async (e: React.FormEvent) => {
54	    e.preventDefault();
55	
56	    const errors = validatePassword(password);
57	    if (errors.length > 0) {
58	      setPasswordErrors(errors);
59	      return;
60	    }
61	
62	    if (password !== confirmPassword) {
63	      toast({
64	        title: "Passwords don't match",
65	        description: "Please make sure both passwords are identical.",
66	        variant: "destructive",
67	      });
68	      return;
69	    }
70	
71	    setIsLoading(true);
72	    const { error } = await supabase.auth.updateUser({ password });
73	    setIsLoading(false);
74	
75	    if (error) {
76	      toast({
77	        title: "Error resetting password",
78	        description: error.message,
79	        variant: "destructive",
80	      });
81	    } else {
82	      toast({
83	        title: "Password updated! 🔒",
84	        description: "Your password has been securely updated.",
85	      });
86	      navigate("/kira");
87	    }
88	  };
89	
90	  if (!isRecovery) {
91	    return (
92	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
93	        <Card className="w-full max-w-md p-8 text-center">
94	          <ShieldCheck className="w-12 h-12 text-bronze mx-auto mb-4" />
95	          <h1 className="font-vollkorn text-2xl font-bold mb-2">Invalid Reset Link</h1>
96	          <p className="text-muted-foreground mb-6">
97	            This link is expired or invalid. Please request a new password reset.
98	          </p>
99	          <Link to="/auth">
100	            <Button className="bg-bronze hover:bg-bronze-dark">Back to Login</Button>
101	          </Link>
102	        </Card>
103	      </div>
104	    );
105	  }
106	
107	  return (
108	    <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
109	      <Card className="w-full max-w-md p-6 md:p-8 animate-fade-in">
110	        <div className="text-center mb-6">
111	          <ShieldCheck className="w-10 h-10 text-bronze mx-auto mb-3" />
112	          <h1 className="font-vollkorn text-2xl md:text-3xl font-bold mb-2">Set New Password</h1>
113	          <p className="text-sm text-muted-foreground">Choose a strong password to protect your account</p>
114	        </div>
115	
116	        <form onSubmit={handleSubmit} className="space-y-4">
117	          <div className="space-y-2">
118	            <Label htmlFor="new-password">New Password</Label>
119	            <div className="relative">
120	              <Input
121	                id="new-password"
122	                type={showPassword ? "text" : "password"}
123	                placeholder="••••••••"
124	                value={password}
125	                onChange={(e) => handlePasswordChange(e.target.value)}
126	                required
127	                className="h-12 pr-12"
128	              />
129	              <button
130	                type="button"
131	                onClick={() => setShowPassword(!showPassword)}
132	                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
133	              >
134	                {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
135	              </button>
136	            </div>
137	          </div>
138	
139	          {password.length > 0 && (
140	            <div className="space-y-1.5">
141	              {["At least 8 characters", "One uppercase letter", "One lowercase letter", "One number", "One special character"].map((rule) => (
142	                <div key={rule} className="flex items-center gap-2 text-xs">
143	                  <div className={cn(
144	                    "w-1.5 h-1.5 rounded-full transition-colors",
145	                    passwordErrors.includes(rule) ? "bg-destructive" : "bg-primary"
146	                  )} />
147	                  <span className={cn(
148	                    "transition-colors",
149	                    passwordErrors.includes(rule) ? "text-muted-foreground" : "text-primary"
150	                  )}>{rule}</span>
151	                </div>
152	              ))}
153	            </div>
154	          )}
155	
156	          <div className="space-y-2">
157	            <Label htmlFor="confirm-password">Confirm Password</Label>
158	            <Input
159	              id="confirm-password"
160	              type={showPassword ? "text" : "password"}
161	              placeholder="••••••••"
162	              value={confirmPassword}
163	              onChange={(e) => setConfirmPassword(e.target.value)}
164	              required
165	              className="h-12"
166	            />
167	          </div>
168	
169	          <Button
170	            type="submit"
171	            disabled={isLoading}
172	            className="w-full h-12 bg-bronze hover:bg-bronze-dark font-semibold"
173	          >
174	            {isLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
175	            {isLoading ? "Updating..." : "Update Password"}
176	          </Button>
177	        </form>
178	      </Card>
179	    </div>
180	  );
181	};
182	
183	export default ResetPassword;
