381	                <div className={cn(
382	                  "w-14 h-14 rounded-2xl flex items-center justify-center transition-all duration-300",
383	                  userType === "creator"
384	                    ? "bg-bronze/20"
385	                    : "bg-muted group-hover:bg-bronze/10"
